// Update does not automatically update the record in case of default values. Use .Reload() to refresh the records.
func (o *PoliticalBelief) Update(ctx context.Context, exec boil.ContextExecutor, columns boil.Columns) (int64, error) {
	var err error
	if err = o.doBeforeUpdateHooks(ctx, exec); err != nil {
		return 0, err
	}
	key := makeCacheKey(columns, nil)
	politicalBeliefUpdateCacheMut.RLock()
	cache, cached := politicalBeliefUpdateCache[key]
	politicalBeliefUpdateCacheMut.RUnlock()

	if !cached {
		wl := columns.UpdateColumnSet(
			politicalBeliefAllColumns,
			politicalBeliefPrimaryKeyColumns,
		)

		if !columns.IsWhitelist() {
			wl = strmangle.SetComplement(wl, []string{"created_at"})
		}
		if len(wl) == 0 {
			return 0, errors.New("entity: unable to update political_beliefs, could not build whitelist")
		}

		cache.query = fmt.Sprintf("UPDATE \"political_beliefs\" SET %s WHERE %s",
			strmangle.SetParamNames("\"", "\"", 1, wl),
			strmangle.WhereClause("\"", "\"", len(wl)+1, politicalBeliefPrimaryKeyColumns),
		)
		cache.valueMapping, err = queries.BindMapping(politicalBeliefType, politicalBeliefMapping, append(wl, politicalBeliefPrimaryKeyColumns...))
		if err != nil {
			return 0, err
		}
	}

	values := queries.ValuesFromMapping(reflect.Indirect(reflect.ValueOf(o)), cache.valueMapping)

	if boil.IsDebug(ctx) {
		writer := boil.DebugWriterFrom(ctx)
		fmt.Fprintln(writer, cache.query)
		fmt.Fprintln(writer, values)
	}
	var result sql.Result
	result, err = exec.ExecContext(ctx, cache.query, values...)
	if err != nil {
		return 0, errors.Wrap(err, "entity: unable to update political_beliefs row")
	}

	rowsAff, err := result.RowsAffected()
	if err != nil {
		return 0, errors.Wrap(err, "entity: failed to get rows affected by update for political_beliefs")
	}

	if !cached {
		politicalBeliefUpdateCacheMut.Lock()
		politicalBeliefUpdateCache[key] = cache
		politicalBeliefUpdateCacheMut.Unlock()
	}

	return rowsAff, o.doAfterUpdateHooks(ctx, exec)
}

